CREATE TABLE employees (
  emp_id     INT PRIMARY KEY,
  first_name VARCHAR(50) NOT NULL,           -- cannot be NULL
  last_name  VARCHAR(50) NOT NULL,           -- cannot be NULL
  email      VARCHAR(80) NOT NULL,
  age        INT CHECK (age >= 18 AND age <= 70),  -- valid working age
  salary     DECIMAL(10,2) CHECK (salary > 0),     -- must be positive
  department VARCHAR(40) NOT NULL DEFAULT 'General'
);

-- Valid inserts
INSERT INTO employees VALUES (1,'Alice','Smith','alice@co.com',28,85000,'Engineering');
INSERT INTO employees VALUES (2,'Bob',  'Jones','bob@co.com',  35,72000,'Marketing');
INSERT INTO employees (emp_id,first_name,last_name,email,age,salary)
  VALUES (3,'Carol','White','carol@co.com',22,65000);  -- department uses DEFAULT

SELECT * FROM employees;

-- This would violate NOT NULL:
-- INSERT INTO employees VALUES (4,NULL,'Brown','dave@co.com',30,50000,'HR');

-- This would violate CHECK age:
-- INSERT INTO employees VALUES (5,'Eve','Davis','eve@co.com',16,30000,'HR');

-- This would violate CHECK salary:
-- INSERT INTO employees VALUES (6,'Frank','Lee','frank@co.com',25,-1000,'HR');

CREATE TABLE users (
  user_id       INT PRIMARY KEY,
  username      VARCHAR(30) UNIQUE NOT NULL,   -- no two users with same username
  email         VARCHAR(80) UNIQUE NOT NULL,   -- email must be unique
  role          VARCHAR(20) DEFAULT 'viewer',  -- default role
  is_active     BOOLEAN DEFAULT TRUE,
  created_at    TIMESTAMP DEFAULT NOW(),
  login_count   INT DEFAULT 0
);

-- Insert users using defaults
INSERT INTO users (user_id, username, email) VALUES (1,'alice','alice@app.com');
INSERT INTO users (user_id, username, email) VALUES (2,'bob','bob@app.com');
INSERT INTO users VALUES (3,'admin_carol','carol@app.com','admin',TRUE,NOW(),0);

SELECT * FROM users;

-- Update login_count to simulate activity
UPDATE users SET login_count = login_count + 1 WHERE user_id = 1;
UPDATE users SET login_count = login_count + 5 WHERE user_id = 3;

SELECT user_id, username, role, login_count FROM users;

-- This would FAIL — duplicate username:
-- INSERT INTO users (user_id,username,email) VALUES (4,'alice','alice2@app.com');

-- This would FAIL — duplicate email:
-- INSERT INTO users (user_id,username,email) VALUES (5,'dave','alice@app.com');

-- Parent table
CREATE TABLE departments (
  dept_id  INT PRIMARY KEY,
  name     VARCHAR(50)
);

-- ON DELETE SET NULL: if department is deleted, employee's dept_id becomes NULL
CREATE TABLE employees_setnull (
  emp_id   INT PRIMARY KEY,
  name     VARCHAR(50),
  dept_id  INT,
  FOREIGN KEY (dept_id) REFERENCES departments(dept_id) ON DELETE SET NULL
);

-- ON DELETE CASCADE: if department is deleted, all its employees are deleted too
CREATE TABLE employees_cascade (
  emp_id   INT PRIMARY KEY,
  name     VARCHAR(50),
  dept_id  INT,
  FOREIGN KEY (dept_id) REFERENCES departments(dept_id) ON DELETE CASCADE
);

INSERT INTO departments VALUES (1,'Engineering'),(2,'Marketing'),(3,'HR');
INSERT INTO employees_setnull VALUES (1,'Alice',1),(2,'Bob',2),(3,'Carol',1);
INSERT INTO employees_cascade VALUES (1,'Dave',1),(2,'Eve', 2),(3,'Frank',1);

-- Delete Engineering department (dept_id=1)
DELETE FROM departments WHERE dept_id = 1;

-- SET NULL result: Alice and Carol have dept_id = NULL
SELECT * FROM employees_setnull ORDER BY emp_id;

-- CASCADE result: Dave and Frank are deleted along with their department
SELECT * FROM employees_cascade ORDER BY emp_id;
